INSERT INTO `kritiria` (`id`, `arxi`, `a_a`, `kritirio`, `analysi`, `barytita`) VALUES
(1, 1, '1.1', 'Αξιολογείται και βαθμολογείται ο βαθμός συνάφειας και επάρκειας των επαγγελματικών προσόντων των αρχηγών εκμεταλλεύσεων ', 'Κατοχή Πτυχίου-Τίτλου Σπουδών Γεωτεχνικής Κατεύθυνσης ανώτερο ή ίσο με επίπεδο 5 του Εθνικού Πλαισίου Προσόντων', 0.1),
(2, 2, '2.1', 'Αξιολογείται και βαθμολογείται η αρχική συμμετοχή σε συλλογικές δράσεις', 'Συμμετοχή σε Ομάδες ή Οργανώσεις παραγωγών', 0.02),
(3, 3, '3.1', 'Αξιολογείται το ετήσιο εισόδημα και πριμοδοτείται η ενίσχυση αρχηγών με χαμηλό ετήσιο εισόδημα', 'Ατομικό ετήσιο εισόδημα έως και 7.500 ευρώ (από κάθε πηγή) και οικογενειακό ετήσιο εισόδημα έως και 20.000 ευρώ (από κάθε πηγή)', 0.06),
(4, 3, '3.2', 'Αξιολογείται η προηγούμενη ιδιότητα ανέργου των αρχηγών εκμεταλλεύσεων', 'Ανεργία πάνω από 1 έτος πριν από την έναρξη πρώτης εγκατάστασης', 0.06),
(5, 4, '4.1', 'Αξιολογούνται τα χαρακτηριστικά του τόπου μόνιμης κατοικίας των αρχηγών εκμεταλλεύσεων(ορεινότητα και νησιωτικότητα)', 'Νησιά με πληθυσμό έως και 3.000 κάτοικοι ή Νησιά που ανήκουν σε μη νησιωτικές περιφέρειες ή Περιοχές που χαρακτηρίζονται ως Ορεινές σύμφωνα με την Οδηγία 75/268/ΕΟΚ ή συνδυασμός αυτών', 0.07),
(6, 4, '4.2', 'Αξιολογούνται τα χαρακτηριστικά του τόπου μόνιμης κατοικίας των αρχηγών εκμεταλλεύσεων (πληθυσμός)', 'Τοπικές ή Δημοτικές Κοινότητες με πληθυσμό έως και 2.500 ή 5.000 κατοίκους', 0.05),
(7, 5, '5.1', 'Αξιολογείται το ποσοστό ιδιοκτησίας στη γεωργική εκμετάλλευση (γεωργική γη και ζωικό κεφάλαιο)', 'Ποσοστό της παραγωγικής δυναμικότητας της εκμετάλλευσης (εκφρασμένη ως αρχική τυπική απόδοση) που προέρχεται από ιδιόκτητη γεωργική γη και ζωικό κεφάλαιο και όταν είναι τουλάχιστον ίσο ή υπερβαίνει το 25% στο σύνολο της εκμετάλλευσης(25%=25, …, 100%=100)', 0.12),
(8, 5, '5.2', 'Αξιολογείται η αρχική παραγωγική δυναμικότητα της εκμετάλλευσης και ενισχύονται αυτές με μέση παραγωγική δυναμικότητα', 'Η παραγωγική δυναμικότητα της εκμετάλλευσης (εκφρασμένη ως αρχική τυπική απόδοση) είναι ίση με 8.000€ - 10.000€ - 15.000€ - 25.000€', 0.1),
(9, 5, '5.3', 'Αξιολογείται η συμβολή του αρχικού προσανατολισμού της γεωργικής εκμετάλλευσης σε τομείς προτεραιότητας για το ΠΑΑ 2014-20', 'Ποσοστό της παραγωγικής δυναμικότητας (εκφρασμένη ως αρχική τυπική απόδοση) που προέρχεται από έναν προωθούμενο από το ΠΑΑ κλάδο, όταν είναι τουλάχιστον ίσο ή υπερβαίνει το 50% στο σύνολο της εκμετάλλευσης με βαρύτητα 1(50%=50, …, 100%=100)', 0.08),
(10, 5, '5.4', 'Αξιολογείται η συμβολή του αρχικού προσανατολισμού της γεωργικής εκμετάλλευσης σε τομείς προτεραιότητας της Στρατηγικής της Περιφέρειας Αττικής', 'Κηπευτικά, Ανθοκομία[Ποσοστό της παραγωγικής δυναμικότητας (εκφρασμένη ως αρχική τυπική απόδοση) που προέρχεται έναν προωθουμενο από την Περιφέρεια, όταν είναι τουλάχιστον ίσο ή υπερβαίνει το 50% στο σύνολο της εκμετάλλευσης, με βαρύτητα 1](50%=50…100%=100)', 0.08),
(11, 6, '6.1', 'Αξιολογείται η  από κοινού \nυποβολή πρότασης για \nυλοποίηση επενδύσεων \nμέσω του υπομέτρου 4.1', 'Από κοινού υποβολή αίτησης για το υπομέτρο 4.1 & \nγια υλοποίηση επε\nνδύσεων μέσω αυτού του \nυπομέτρου', 0.02),
(12, 7, '7.1', 'Αξιολογείται η συμβολή του επιχειρηματικού σχεδίου στο στόχο του ΠΑΑ 2014-20 για την παραγωγή ποιοτικών προϊόντων', 'Το επιχειρηματικό σχέδιο συμβάλλει στην παραγωγή ποιοτικών προϊόντων βιολογικής παραγωγής ή ολοκληρωμένης διαχείρισης εφόσον αφορά ποσοστό της παραγωγικής δυναμικότητας της εκμετάλλευσης (εκφρασμένη ως τελική τυπική απόδοση) που είναι τουλάχιστον ίσο ή υπερβαίνει το 40% στο σύνολο της εκμετάλλευσης', 0.06),
(13, 7, '7.2', 'Αξιολογείται η συμβολή του επιχειρηματικού σχεδίου σε τομείς προτεραιότητας του ΠΑΑ 2014-20', 'Το επιχειρηματικό σχέδιο συμβάλει κατά κύριο λόγο στον σε έναν προωθούμενο από το ΠΑΑ τομέα εφόσον ποσοστό της παραγωγικής δυναμικότητας της εκμετάλλευσης (εκφρασμένη ως τελική τυπική απόδοση) που είναι τουλάχιστον ίσο ή υπερβαίνει το 50% στο σύνολο της εκμετάλλευσης προέρχεται από αυτό τον τομέα', 0.07),
(14, 7, '7.3', 'Αξιολογείται η συμβολή του επιχειρηματικού σχεδίου σε στόχους και τομείς προτεραιότητας της Στρατηγικής της Περιφέρειας Αττικής', 'Κηπευτικά, Ανθοκομία[Το επιχειρηματικό σχέδιο συμβάλει κατά κύριο λόγο σε έναν προωθούμενο από την Περιφέρεια τομέα, εφόσον ποσοστό της παραγωγικής δυναμικότητας της εκμετάλλευσης (εκφρασμένη ως τυπική απόδοση) που είναι τουλάχιστον ίσο ή υπερβαίνει το 50% στο σύνολο της εκμετάλλευσης προέρχεται από τους εν λόγω τομείς]', 0.13);
